var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"……목숨은 장담할 수 없겠지만.","JPN":"……命の保証はしかねるがな。","ENG":"... I can't guarantee you'll come out alive.","TWN":"雖然……不保證性命無虞。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그렇다고 날 인질로 잡는 건 추천하지 않아. 내게는 그럴 가치가 없거든.","JPN":"だからと言って、私を人質にすることはお勧めしない。私にはその価値がないのでね。","ENG":"But then again, I don't recommend you take me hostage. It's just not worth it.","TWN":"但我不建議你抓我當人質，因為我沒資格當人質。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그 몸이 기계로 만들어졌기 때문입니까?","JPN":"その身体が機械でできているからですか？","ENG":"Because your body is a machine?","TWN":"因為你的身體是機械嗎？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"좋은 안목이군. 맨션에서 식기류를 관리하며 터득한 건가?","JPN":"目がいいな。マンションで食器類を管理しながら身につけたのかね？","ENG":"You have a good eye. Did you develop that insight while managing the dishes at Mansion?","TWN":"好眼力，是在曼森管理餐具時培養出來的嗎？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"퓨처 앳 워에 남아 있던 연구 자료를 참고했어. 아직은 걸음마 수준에 불과하지만 말이야.","JPN":"フューチャーアットウォーに残っていた研究資料を参考にしたのだ。まだ初歩的な段階に過ぎないがな。","ENG":"I referred to the research material Future-at-War left. Even if it's still in its infancy stage.","TWN":"我有參考過天啓兵器中遺留的研究資料，雖然還在起步階段而已。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"충고 하나 해 주지. 여기서 나를 파괴한들 아버지에게는 득이 되지 않아.","JPN":"一つ忠告しておこう。ここで私を破壊しても父が得することは何もない。","ENG":"Here's a little piece of advice. Destroying me here will do nothing for Father.","TWN":"給你個忠告，在這裡毀掉我，對爸爸沒有任何好處。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"오히려 다른 평의회 구성원들의 돌발 행동으로 변수만 늘어날 걸세.","JPN":"むしろ評議会の他のメンバーによる突発的な行動で変数が増えるだけだ。","ENG":"However, it will bring more uncontrolled variables by the other members of the Dark Council.","TWN":"反而會因為其他評議會成員的突發行動，而增加更多變數。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"당신 덕분에 평화를 누릴 수 있다는 말처럼 들리는군요.","JPN":"あなたのおかげで平和な生活ができるかのような口ぶりですね。","ENG":"You make it sound like we have peace because of you.","TWN":"聽起來像是拜你所賜才能享有和平的樣子。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"평화와 균형의 사자가 되기 위해 항상 노력하고 있지.","JPN":"平和と均衡の使者になるために常に努力している。","ENG":"I'm always doing my best to become the messenger of peace and balance.","TWN":"我一直很努力要成為和平大使。"},"stage":{"bg":"CAR","slots":{"L":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"알겠습니다. 주인님께서 초월적인 존재들과 맞서신다는 이야기는 잠시 접어 두죠.","JPN":"わかりました。ご主人様が超越的な存在と向き合っているという話はやめておきましょう。","ENG":"All right. I'll put aside the talk about Master confronting transcendent beings for now.","TWN":"好吧，先不說主人和超自然存在對抗的事。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"주인님의 계획이 결과적으로 실패할 거라고 확신하는 근거가 무엇입니까?","JPN":"ご主人様の計画が結果的には失敗すると確信する根拠は何ですか？","ENG":"But what makes you certain that Master's plans will fail?","TWN":"你肯定主人的計畫最終會失敗的根據是什麼呢？"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"정 때문이야, 베로니카.","JPN":"情だ、ベロニカ。","ENG":"It's because of emotion, Veronica.","TWN":"因為感情用事。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"살인만을 배우고 자란 자네를 밝은 빛 아래에서 지낼 수 있게 이끌어 준 그 정.","JPN":"殺人だけを教えられながら育った君を、明るい光の下で暮らせるようにしたあの情。","ENG":"The same emotion that allowed a cold-blooded killer like you to step into the light.","TWN":"因為感情用事，才會想將只學過殺人的你，帶到陽光底下生活。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"우리의 자랑스러운 아버지는 뼛속까지 인간이었어.","JPN":"我が自慢の父上は骨の髄まで人間だった。","ENG":"My proud Father was that kind of person down to his core.","TWN":"我偉大的爸爸連骨子裡都是人類。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"마지막까지 한 줌의 정 때문에 일을 그르치고 만다. 그렇게 정해져 있지.","JPN":"最後の最後に取るに足らない情のせいで失敗してしまう。そう決まっているのだ。","ENG":"He messes everything up at the end all because of emotion. It's just how it is.","TWN":"到最後都因為感情用事而壞事，這是已知的結果。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"그저 냉혹하기만 하셨다면, 저는 그 분을 주인으로 모시지 않았을 겁니다.","JPN":"冷酷なだけの方であったなら、私はあの方を主として認めなかったはずです。","ENG":"If he was a cold human being, I would've never served him as my master.","TWN":"若主人是那麼冷酷的人，我是不可能認他為主人的。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"물론 그렇겠지.","JPN":"もちろんそうだろう。","ENG":"Of course.","TWN":"那是當然的。"},"stage":{"bg":"CAR","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};